$dir = 'images';
if (!is_dir($dir)) {
    mkdir($dir, 0755, true);
}

$b64_data = '';
$img_data = base64_decode($b64_data);

if (file_put_contents('images/logo.png', $img_data)) {
    echo "Success: images/logo.png has been generated.";
} else {
    echo "Error: Failed to write images/logo.png.";
}
?>